module RefModule(
    input clk,
    input rst,
    input en,
    input dir,
    output reg [7:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
  if (rst)
    count <= 0;
  else if (en)
    if (dir)
      count <= count + 1;
    else
      count <= count - 1;
end

endmodule
